def find_repeated_substrings(s, k, base=256, mod=10**9 + 7):
    n = len(s)
    if k > n:
        return []
    high_order = pow(base, k - 1, mod)
    window_hash = 0
    for i in range(k):
        window_hash = (window_hash * base + ord(s[i])) % mod

    seen = {window_hash: [s[0:k]]}
    repeated = set()
    for i in range(1, n - k + 1):
        window_hash = (window_hash - ord(s[i - 1]) * high_order) % mod
        window_hash = (window_hash * base + ord(s[i + k - 1])) % mod
        window_hash %= mod
        substring = s[i:i + k]
        if window_hash in seen:
            if substring in seen[window_hash]:
                repeated.add(substring)
            else:
                seen[window_hash].append(substring)
        else:
            seen[window_hash] = [substring]
    return list(repeated)

def find_anagram_starts(text, pattern):
    from collections import Counter
    m = len(pattern)
    if m > len(text):
        return []
    need = Counter(pattern)
    window = Counter(text[:m])
    positions = []
    if window == need:
        positions.append(0)
    for i in range(m, len(text)):
        window[text[i]] += 1
        left_char = text[i - m]
        window[left_char] -= 1
        if window[left_char] == 0:
            del window[left_char]
        if window == need:
            positions.append(i - m + 1)
    return positions

