def nearest_element(arr, mode='next_greater'):
    """
    mode in {'next_greater', 'next_smaller', 'prev_greater', 'prev_smaller'}
    Returns result[i] = index of the nearest qualifying neighbor, or -1.
    """
    n = len(arr)
    result = [-1] * n
    stack = []
    greater = 'greater' in mode
    is_next = mode.startswith('next')

    for i in range(n):
        while stack and ((arr[stack[-1]] < arr[i]) if greater else (arr[stack[-1]] > arr[i])):
            popped = stack.pop()
            if is_next:
                result[popped] = i          # i is the 'next' qualifying index for popped
        if not is_next:
            result[i] = stack[-1] if stack else -1  # top of stack is the 'previous' qualifying index
        stack.append(i)

    return result

