def min_bottleneck_to_connect(num_vertices, edges):
    parent = list(range(num_vertices))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        root_x, root_y = find(x), find(y)
        if root_x == root_y:
            return False
        parent[root_y] = root_x
        return True

    edges_sorted = sorted(edges, key=lambda e: e[2])
    components = num_vertices
    bottleneck = 0

    for u, v, w in edges_sorted:
        if union(u, v):
            bottleneck = w
            components -= 1
            if components == 1:
