def prim_mst_dense(num_vertices, adj_matrix):
    INF = float('inf')
    in_mst = [False] * num_vertices
    min_edge = [INF] * num_vertices
    min_edge[0] = 0
    total_cost = 0

    for _ in range(num_vertices):
        u = -1
        for v in range(num_vertices):
            if not in_mst[v] and (u == -1 or min_edge[v] < min_edge[u]):
                u = v

        if min_edge[u] == INF:
            return -1  # graph is disconnected

        in_mst[u] = True
        total_cost += min_edge[u]

        for v in range(num_vertices):
            if not in_mst[v] and adj_matrix[u][v] != 0 and adj_matrix[u][v] < min_edge[v]:
                min_edge[v] = adj_matrix[u][v]

    return total_cost

