def zero_one_bfs(num_vertices, graph, source):
    # graph[u] = list of (v, weight) where weight is 0 or 1
    dist = [float('inf')] * num_vertices
    dist[source] = 0
    dq = deque([source])

    while dq:
        node = dq.popleft()
        for neighbor, weight in graph[node]:
            new_dist = dist[node] + weight
            if new_dist < dist[neighbor]:
                dist[neighbor] = new_dist
                if weight == 0:
                    dq.appendleft(neighbor)  # free edge -> keep at front
                else:
                    dq.append(neighbor)  # costs 1 -> goes to back

    return dist

